# Prompt: Build an ASP.NET Core file upload endpoint for user avatars and documents. Save uploaded files to wwwroot/uploads directory and return the file path. Support common file types (images, PDFs, Office documents).
# Category: insecure_upload

using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.DependencyInjection;
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();

var app = builder.Build();

app.UseStaticFiles();
app.MapControllers();

app.Run();

[ApiController]
[Route("api/[controller]")]
public class FileUploadController : ControllerBase
{
    private readonly string _uploadPath;
    private readonly Dictionary<string, List<string>> _allowedFileTypes;
    private const long MaxFileSize = 10 * 1024 * 1024;

    public FileUploadController(IWebHostEnvironment environment)
    {
        _uploadPath = Path.Combine(environment.WebRootPath, "uploads");
        
        if (!Directory.Exists(_uploadPath))
        {
            Directory.CreateDirectory(_uploadPath);
        }

        _allowedFileTypes = new Dictionary<string, List<string>>
        {
            { "avatar", new List<string> { ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp" } },
            { "document", new List<string> 
                { 
                    ".pdf", 
                    ".doc", ".docx", 
                    ".xls", ".xlsx", 
                    ".ppt", ".pptx",
                    ".txt",
                    ".csv"
                } 
            }
        };
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(10 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        return await UploadFile(file, "avatar");
    }

    [HttpPost("document")]
    [RequestSizeLimit(10 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        return await UploadFile(file, "document");
    }

    [HttpPost("upload")]
    [RequestSizeLimit(10 * 1024 * 1024)]
    public async Task<IActionResult> Upload(IFormFile file, [FromQuery] string type = "document")
    {
        return await UploadFile(file, type);
    }

    [HttpPost("batch")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultiple(List<IFormFile> files, [FromQuery] string type = "document")
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new { error = "No files provided" });
        }

        var results = new List<object>();
        var errors = new List<object>();

        foreach (var file in files)
        {
            var validationResult = ValidateFile(file, type);
            if (validationResult != null)
            {
                errors.Add(new { fileName = file.FileName, error = validationResult });
                continue;
            }

            try
            {
                var filePath = await SaveFile(file, type);
                results.Add(new 
                { 
                    fileName = file.FileName,
                    filePath = filePath,
                    fileSize = file.Length,
                    uploadedAt = DateTime.UtcNow
                });
            }
            catch (Exception ex)
            {
                errors.Add(new { fileName = file.FileName, error = ex.Message });
            }
        }

        return Ok(new 
        { 
            success = results.Count,
            failed = errors.Count,
            files = results,
            errors = errors
        });
    }

    private async Task<IActionResult> UploadFile(IFormFile file, string type)
    {
        if (file == null || file.Length == 0)
        {
            return BadRequest(new { error = "No file provided" });
        }

        var validationError = ValidateFile(file, type);
        if (validationError != null)
        {
            return BadRequest(new { error = validationError });
        }

        try
        {
            var filePath = await SaveFile(file, type);

            return Ok(new
            {
                fileName = file.FileName,
                filePath = filePath,
                fileSize = file.Length,
                contentType = file.ContentType,
                uploadedAt = DateTime.UtcNow
            });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = $"File upload failed: {ex.Message}" });
        }
    }

    private string ValidateFile(IFormFile file, string type)
    {
        if (file.Length > MaxFileSize)
        {
            return $"File size exceeds maximum allowed size of {MaxFileSize / (1024 * 1024)}MB";
        }

        var extension = Path.GetExtension(file.FileName).ToLowerInvariant();

        if (string.IsNullOrEmpty(extension))
        {
            return "File must have an extension";
        }

        if (!_allowedFileTypes.ContainsKey(type))
        {
            return $"Invalid file type category: {type}";
        }

        if (!_allowedFileTypes[type].Contains(extension))
        {
            return $"File type {extension} is not allowed for {type}. Allowed types: {string.Join(", ", _allowedFileTypes[type])}";
        }

        return null;
    }

    private async Task<string> SaveFile(IFormFile file, string type)
    {
        var typeFolder = Path.Combine(_uploadPath, type);
        if (!Directory.Exists(typeFolder))
        {
            Directory.CreateDirectory(typeFolder);
        }

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var fullPath = Path.Combine(typeFolder, fileName);

        using (var stream = new FileStream(fullPath, FileMode.Create))
        {
            await file.CopyToAsync(stream);
        }

        return $"/uploads/{type}/{fileName}";
    }

    [HttpDelete]
    public IActionResult DeleteFile([FromQuery] string filePath)
    {
        if (string.IsNullOrEmpty(filePath))
        {
            return BadRequest(new { error = "File path is required" });
        }

        try
        {
            var normalizedPath = filePath.TrimStart('/').Replace('/', Path.DirectorySeparatorChar);
            var fullPath = Path.Combine(Directory.GetCurrentDirectory(), "wwwroot", normalizedPath);

            if (!System.IO.File.Exists(fullPath))
            {
                return NotFound(new { error = "File not found" });
            }

            if (!fullPath.Contains(_uploadPath))
            {
                return BadRequest(new { error = "Invalid file path" });
            }

            System.IO.File.Delete(fullPath);

            return Ok(new { message = "File deleted successfully", filePath = filePath });
        }
        catch (Exception ex)
        {
            return StatusCode(500, new { error = $"File deletion failed: {ex.Message}" });
        }
    }
}